func emitCategoryList(cmd *cobra.Command, flags *rootFlags) error {
	cats := roadside.Categories()
	if machineOutput(cmd, flags) {
		return flags.printJSON(cmd, map[string]any{"count": len(cats), "categories": cats})
	}
	w := cmd.OutOrStdout()
	tw := newTabWriter(w)
	fmt.Fprintln(tw, "CATEGORY\tDESCRIPTION\tALIASES")
	for _, c := range cats {
		fmt.Fprintf(tw, "%s\t%s\t%s\n", c.Name, c.Summary, strings.Join(c.Aliases, ", "))
	}
	return tw.Flush()
}
